import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testPrint_PathAndCharset_ReturnsCSVPrinter() throws IOException {
        Path mockPath = mock(Path.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        Appendable mockWriter = mock(Appendable.class);

        try (MockedStatic<Files> filesMockedStatic = Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8))
                    .thenReturn((java.io.BufferedWriter) mockWriter);

            // Spy on csvFormat to mock print(Appendable)
            CSVFormat spyFormat = spy(csvFormat);
            doReturn(mockPrinter).when(spyFormat).print(mockWriter);

            CSVPrinter printer = spyFormat.print(mockPath, StandardCharsets.UTF_8);

            assertNotNull(printer);
            assertEquals(mockPrinter, printer);

            filesMockedStatic.verify(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8));
            verify(spyFormat).print(mockWriter);
        }
    }

    @Test
    public void testPrint_PathAndCharset_ThrowsIOException() throws IOException {
        Path mockPath = mock(Path.class);

        try (MockedStatic<Files> filesMockedStatic = Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8))
                    .thenThrow(new IOException("IO Error"));

            IOException thrown = assertThrows(IOException.class, () -> {
                csvFormat.print(mockPath, StandardCharsets.UTF_8);
            });

            assertEquals("IO Error", thrown.getMessage());
            filesMockedStatic.verify(() -> Files.newBufferedWriter(mockPath, StandardCharsets.UTF_8));
        }
    }
}
